class Tactic:
    def __init__(self):
        self.cover_x = 22
        self.at_cover = False
    def tick(self, me, world):
        if not self.at_cover:
            dest = (self.cover_x, me.pos[1])
            path = world.path(dest)
            if path and len(path) > 1:
                return me.move_toward(path[1])
            else:
                return me.move_toward(dest)
        if me.cooldown == 0:
            enemies = world.visible_enemies()
            in_range = [e for e in enemies if me.distance_to(e) <= me.range]
            if in_range:
                target = min(in_range, key=lambda e: me.distance_to(e))
                return me.attack(target)
        return me.move_toward(world.enemy_spawn)

