class Tactic:
    def __init__(self):
        pass
    def tick(self, me, world):
        if me.hp / me.max_hp < 0.3:
            return me.move_toward(world.my_spawn)
        allies = world.visible_allies()
        low_hp = [a for a in allies if a.hp / a.max_hp < 0.5]
        if low_hp and me.cooldown == 0:
            target = min(low_hp, key=lambda a: a.hp)
            return me.heal(target)
        if allies:
            ally = min(allies, key=lambda a: me.distance_to(a))
            return me.move_toward(ally.pos)
        return me.move_toward(world.my_spawn)

tactics.drone:
class Tactic:
    def __init__(self):
        self.retreat_until = 0
    def tick(self, me, world):
        for e in world.visible_enemies():
            me.broadcast("E:" + str(e.pos[0]) + "," + str(e.pos[1]))
        if me.hp / me.max_hp < 0.3:
            self.retreat_until = world.tick + 6
        if world.tick < self.retreat_until:
            return me.move_toward(world.my_spawn)
        if me.cooldown == 0:
            close = [e for e in world.visible_enemies() if me.distance_to(e) <= me.range]
            if close:
                target = min(close, key=lambda e: e.hp)
                return me.attack(target)
        return me.move_toward(world.enemy_spawn)
